interface KPIItem {
  label: string;
  target: string;
  unit: string;
  icon?: React.ElementType;
}

interface KPICategory {
  title: string;
  color: string;
  items: KPIItem[];
  icon: any;
}

interface LayoutProps {
  title: string;
  subtitle: string;
  features?: Feature[][]; // For structured KPIs
}

