      icon: TrendingUp,
      items: [
        { label: "Follower Growth", target: "+25", unit: "%/Q" },
        { label: "Post Engagement", target: "> 5", unit: "%" },
        { label: "Monthly Impressions", target: "1M+", unit: "Hits" }
